import sys
import pkgutil
import io

def find_cycle(module_name, seen=None):
    if seen is None:
        seen = set()
    try:
        package = __import__(module_name, fromlist=[sys.argv[0]]))
        if module_name in seen:
            raise ImportError(f"Circular import detected: {module_name}
	Found in:
	{', '.join(seen)}
	Resolve dependencies to break the cycle.
")
        seen.add(module_name)
        for name, obj in pkgutil.walk_packages(\n            sys.modules[package.__path__]):
            if find_cycle(name, seen):
                pass
    except ImportError as e:
        print(e)\```

